import React, { useState } from "react";
import ReactModal from "react-modal";
import { TransformWrapper, TransformComponent } from "react-zoom-pan-pinch";
import { FaExpand, FaCompress, FaSearchPlus, FaSearchMinus } from "react-icons/fa";
import "./ImageModal.css";

ReactModal.setAppElement("#root");

export default function ImageModal({ isOpen, onRequestClose, imageUrl }) {
  const [isFullScreen, setIsFullScreen] = useState(false);

  const toggleFullScreen = () => {
    setIsFullScreen(!isFullScreen);
  };

  return (
    <ReactModal
      isOpen={isOpen}
      onRequestClose={onRequestClose}
      className={isFullScreen ? "modal-content fullscreen" : "modal-content"}
      overlayClassName="modal-overlay"
    >
      <button className="modal-close" onClick={onRequestClose}>
        &times;
      </button>

      <TransformWrapper
        initialScale={1}
        minScale={0.5}
        maxScale={10}
        wheel={{ step: 0.1 }}
        doubleClick={{ disabled: true }}
      >
        {({ zoomIn, zoomOut, resetTransform, zoomLevel }) => (
          <>
            <div className="tools-container">
              <button onClick={zoomIn} aria-label="Zoom In">
                <FaSearchPlus />
              </button>
              <button onClick={zoomOut} aria-label="Zoom Out">
                <FaSearchMinus />
              </button>
              <button onClick={resetTransform} aria-label="Reset Zoom">
                Reset
              </button>
            </div>
            <TransformComponent>
              <img
                src={imageUrl}
                alt="Zoomable"
                style={{ width: "100%", height: "auto", userSelect: "none" }}
              />
            </TransformComponent>
          </>
        )}
      </TransformWrapper>

      <button className="fullscreen-btn" onClick={toggleFullScreen} aria-label="Toggle Fullscreen">
        {isFullScreen ? <FaCompress /> : <FaExpand />}
      </button>
    </ReactModal>
  );
}
